import{_ as e,o as i,c as a,ag as n}from"./chunks/framework.BZohXCq9.js";const k=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md"}'),t={name:"getting-started/index.md"};function l(r,s,p,o,h,d){return i(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>Get up and running with Helix Scripts in minutes.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A FiveM server running the latest recommended artifacts</li><li>One of the supported frameworks: <strong>Qbox</strong>, <strong>QBCore</strong>, or <strong>ESX</strong> (or standalone mode)</li><li>Lua 5.4 enabled in your server (<code>lua54 &#39;yes&#39;</code> in fxmanifest — helix_lib handles this)</li><li>Node.js 18+ (only if you plan to build NUI from source)</li></ul><h2 id="step-1-—-download-helix-lib" tabindex="-1">Step 1 — Download helix_lib <a class="header-anchor" href="#step-1-—-download-helix-lib" aria-label="Permalink to &quot;Step 1 — Download helix_lib&quot;">​</a></h2><p><code>helix_lib</code> is the shared library that powers every Helix script. <strong>All other Helix resources depend on it</strong>, so it must be installed first.</p><ol><li>Download the latest release from the <a href="https://github.com/Helix-Scripts/helix-lib/releases" target="_blank" rel="noreferrer">GitHub releases page</a>.</li><li>Extract the folder into your server&#39;s <code>resources/</code> directory.</li><li>Rename it to <code>helix_lib</code> (underscore, not hyphen) if the zip extracts with a different name.</li></ol><div class="warning custom-block"><p class="custom-block-title">Resource naming</p><p>The folder <strong>must</strong> be named <code>helix_lib</code> (with an underscore). FiveM resource names follow folder names, and all Helix scripts reference <code>helix_lib</code> in their exports.</p></div><h2 id="step-2-—-add-to-server-cfg" tabindex="-1">Step 2 — Add to server.cfg <a class="header-anchor" href="#step-2-—-add-to-server-cfg" aria-label="Permalink to &quot;Step 2 — Add to server.cfg&quot;">​</a></h2><p>Open your <code>server.cfg</code> and ensure <code>helix_lib</code> starts <strong>before</strong> any other Helix script:</p><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ensure helix_lib</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Then your other Helix scripts (order matters)</span></span>
<span class="line"><span>ensure helix_hud</span></span>
<span class="line"><span>ensure helix_npc</span></span>
<span class="line"><span>ensure helix_economy</span></span>
<span class="line"><span># etc.</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Start order matters</p><p><code>helix_lib</code> <strong>must</strong> start before all other Helix resources. If it is not running, dependent scripts will fail with export-not-found errors.</p></div><h2 id="step-3-—-configure" tabindex="-1">Step 3 — Configure <a class="header-anchor" href="#step-3-—-configure" aria-label="Permalink to &quot;Step 3 — Configure&quot;">​</a></h2><p>Edit <code>config.lua</code> in the <code>helix_lib</code> resource folder:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    -- Enable debug logging (verbose output, dev tools)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    debug </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    -- Default locale for translations</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    locale </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;en&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    -- Framework override (auto-detected if nil)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    -- Options: &#39;qbox&#39;, &#39;qbcore&#39;, &#39;esx&#39;, &#39;standalone&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    framework </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> nil</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    -- Check GitHub for updates on startup</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    versionCheck </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    -- Notification defaults</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    notifications </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        position </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;top-right&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        duration </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    -- Log level: &#39;error&#39;, &#39;warn&#39;, &#39;info&#39;, &#39;debug&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    logging </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        level </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;info&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>See the <a href="./configuration.html">Configuration guide</a> for details on each option.</p><h2 id="step-4-—-restart" tabindex="-1">Step 4 — Restart <a class="header-anchor" href="#step-4-—-restart" aria-label="Permalink to &quot;Step 4 — Restart&quot;">​</a></h2><p>Restart your server (or run <code>ensure helix_lib</code> in the live console). You should see:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╔═══════════════════════════════════════╗</span></span>
<span class="line"><span>║         helix_lib v0.1.0              ║</span></span>
<span class="line"><span>║         Framework: qbox               ║</span></span>
<span class="line"><span>║         Locale: en                    ║</span></span>
<span class="line"><span>╚═══════════════════════════════════════╝</span></span></code></pre></div><p>If the framework shows <code>standalone</code> and you expected a framework to be detected, check that your framework resource (<code>qbx_core</code>, <code>qb-core</code>, or <code>es_extended</code>) starts <strong>before</strong> <code>helix_lib</code>.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./configuration.html">Configuration</a> — understand all config options</li><li><a href="/scripts/helix-lib.html">helix_lib overview</a> — explore the full feature set</li><li><a href="/api/">API Reference</a> — complete export documentation</li><li><a href="/guides/framework-bridge.html">Framework Bridge Guide</a> — framework-specific details</li></ul>`,22)])])}const g=e(t,[["render",l]]);export{k as __pageData,g as default};
